using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpRestServer;

[McpServerToolType]
public sealed class PostTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    public PostTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool, Description("Get a list of posts, optionally filtered by user ID.")]
    public async Task<string> GetPosts(
        [Description("Filter posts by user ID")] int? userId = null)
    {
        using var client = _httpClientFactory.CreateClient("api");
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        var posts = await client.GetFromJsonAsync<List<Post>>(url);
        return System.Text.Json.JsonSerializer.Serialize(posts);
    }

    [McpServerTool, Description("Get a single post by its ID.")]
    public async Task<string> GetPost(
        [Description("The post ID to retrieve")] int id)
    {
        using var client = _httpClientFactory.CreateClient("api");
        var post = await client.GetFromJsonAsync<Post>($"/posts/{id}");
        return System.Text.Json.JsonSerializer.Serialize(post);
    }

    [McpServerTool, Description("Create a new post.")]
    public async Task<string> CreatePost(
        [Description("Title of the post")] string title,
        [Description("Body content of the post")] string body,
        [Description("Author user ID")] int userId)
    {
        using var client = _httpClientFactory.CreateClient("api");
        var response = await client.PostAsJsonAsync("/posts", new { title, body, userId });
        var result = await response.Content.ReadAsStringAsync();
        return result;
    }
}

public record Post(
    [property: JsonPropertyName("userId")] int UserId,
    [property: JsonPropertyName("id")] int Id,
    [property: JsonPropertyName("title")] string Title,
    [property: JsonPropertyName("body")] string Body);

